// src/pages/AdminCourses.js
import React, { useEffect, useState } from 'react';
import { coursesService } from '../services/courses';
import { adminService } from '../services/admin';

const AdminCourses = () => {
  const [pendingCourses, setPendingCourses] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPendingCourses = async () => {
      try {
        const allCourses = await coursesService.getAll();
        const pending = allCourses.results.filter(
          course => !course.is_approved
        );
        setPendingCourses(pending);
      } catch (error) {
        console.error('Error fetching courses:', error);
      } finally {
        setLoading(false);
      }
    };
    fetchPendingCourses();
  }, []);

  const handleApprove = async (id) => {
    try {
      await adminService.approveCourse(id);
      setPendingCourses(prev => prev.filter(course => course.id !== id));
    } catch {
      alert('فشل الموافقة');
    }
  };

  const handleReject = async (id) => {
    try {
      await adminService.rejectCourse(id);
      setPendingCourses(prev => prev.filter(course => course.id !== id));
    } catch {
      alert('فشل الرفض');
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <h2 style={styles.title}>📚 Pending Courses</h2>

        {loading ? (
          <p style={styles.loading}>Loading...</p>
        ) : pendingCourses.length === 0 ? (
          <p style={styles.empty}>No pending courses 🎉</p>
        ) : (
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>العنوان</th>
                <th style={styles.th}>المُدرّس</th>
                <th style={styles.th}>الإجراءات</th>
              </tr>
            </thead>
            <tbody>
              {pendingCourses.map(course => (
                <tr key={course.id} style={styles.tr}>
                  <td>{course.title}</td>
                  <td>{course.instructor.email}</td>
                  <td>
                    <button
                      onClick={() => handleApprove(course.id)}
                      style={{ ...styles.button, ...styles.approve }}
                    >
                      ✔ Approve
                    </button>
                    <button
                      onClick={() => handleReject(course.id)}
                      style={{ ...styles.button, ...styles.reject }}
                    >
                      ✖ Reject
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

const styles = {
  page: {
    background: '#f4f6f8',
    minHeight: '100vh',
    padding: '40px',
  },
  card: {
    background: '#fff',
    borderRadius: '12px',
    padding: '25px',
    boxShadow: '0 10px 25px rgba(0,0,0,0.08)',
  },
  title: {
    marginBottom: '20px',
  },
  loading: {
    textAlign: 'center',
    color: '#666',
  },
  empty: {
    textAlign: 'center',
    color: '#999',
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse',
  },
  th: {
    textAlign: 'left',
    padding: '12px',
    borderBottom: '1px solid #eee',
    color: '#555',
  },
  tr: {
    borderBottom: '1px solid #f0f0f0',
  },
  button: {
    padding: '8px 14px',
    borderRadius: '6px',
    border: 'none',
    cursor: 'pointer',
    marginRight: '10px',
    fontWeight: '500',
  },
  approve: {
    backgroundColor: '#28a745',
    color: '#fff',
  },
  reject: {
    backgroundColor: '#dc3545',
    color: '#fff',
  },
};

export default AdminCourses;
